import { Component } from '@angular/core';

@Component({
  selector: 'bo-user-management',
  templateUrl: './user-management.component.html',
  styleUrls: ['./user-management.component.css']
})
export class UserManagementComponent {
  isLoading = false;

  // Placeholder: backend needs /admin/users endpoints
  users: any[] = [];
}
<div class="bg-white rounded-lg shadow">
  <div class="px-6 py-4 border-b border-gray-200">
    <h3 class="text-lg font-semibold text-gray-900">Gestion de Usuarios</h3>
    <p class="text-sm text-gray-500 mt-1">Administrar usuarios, roles y permisos del sistema.</p>
  </div>

  <div class="p-6">
    <div class="text-gray-500 text-sm">
      <p class="mb-2">Esta funcionalidad requiere endpoints adicionales en el backend:</p>
      <ul class="list-disc list-inside space-y-1 text-gray-400">
        <li>GET /admin/users - Listar usuarios</li>
        <li>POST /admin/users - Crear usuario</li>
        <li>PATCH /admin/users/id/roles - Actualizar roles</li>
        <li>PATCH /admin/users/id/status - Activar/desactivar</li>
      </ul>
    </div>
  </div>
</div>
